def heuristic_pipeline_health_warn(name: str, cfg: dict, today_str: str) -> tuple:
    """Detect strategies boosted but silent for 7+ days -- likely pipeline break."""
    if not cfg.get("enabled", False):
        return False, ""
    mult = cfg.get("size_multiplier", 1.0)
    if mult <= 1.0:
        return False, ""
    if cfg.get("trades_7d", 0) > 0:
        return False, ""
    enabled_at = cfg.get("enabled_at")
    if not enabled_at:
        return False, ""
    try:
        from datetime import date as _date
        days_since = (_date.fromisoformat(today_str) - _date.fromisoformat(enabled_at)).days
    except Exception:
        return False, ""
    if days_since >= 7:
        return True, f"PIPELINE_HEALTH_WARN: boosted {mult:.1f}x but 0 trades in {days_since}d -- monitor pipeline suspect"
    return False, ""

