class TestPipelineHealthWarn(unittest.TestCase):
    def test_fires_on_boosted_silent(self):
        cfg = {"enabled": True, "size_multiplier": 1.5, "trades_7d": 0, "enabled_at": "2026-05-19"}
        fired, reason = heuristic_pipeline_health_warn("crypto-momentum", cfg, "2026-06-06")
        self.assertTrue(fired)
        self.assertIn("PIPELINE_HEALTH_WARN", reason)

    def test_no_fire_if_trades_present(self):
        cfg = {"enabled": True, "size_multiplier": 1.5, "trades_7d": 1, "enabled_at": "2026-05-19"}
        fired, _ = heuristic_pipeline_health_warn("crypto-momentum", cfg, "2026-06-06")
        self.assertFalse(fired)

    def test_no_fire_if_not_boosted(self):
        cfg = {"enabled": True, "size_multiplier": 1.0, "trades_7d": 0, "enabled_at": "2026-05-19"}
        fired, _ = heuristic_pipeline_health_warn("x", cfg, "2026-06-06")
        self.assertFalse(fired)

    def test_no_fire_if_recently_enabled(self):
        cfg = {"enabled": True, "size_multiplier": 1.5, "trades_7d": 0, "enabled_at": "2026-06-04"}
        fired, _ = heuristic_pipeline_health_warn("x", cfg, "2026-06-06")
        self.assertFalse(fired)

    def test_no_fire_if_disabled(self):
        cfg = {"enabled": False, "size_multiplier": 1.5, "trades_7d": 0, "enabled_at": "2026-05-19"}
        fired, _ = heuristic_pipeline_health_warn("x", cfg, "2026-06-06")
        self.assertFalse(fired)
